{
  "name": "CondoManage Pro",
  "description": "A comprehensive condominium management application for small buildings (under 8 units), featuring expense tracking, millesimal division, document storage, financial reporting, and an AI-powered legal wiki.",
  "requestFramePermissions": [
    "camera"
  ]
}

export interface Owner {
  id: string;
  name: string;
  unit: string;
  millesimi: number;
  email: string;
  phone: string;
}

export interface Payment {
  id: string;
  ownerId: string;
  amount: number;
  date: string;
  type: 'Quota' | 'Straordinario';
  description: string;
}

export interface Expense {
  id: string;
  description: string;
  category: string;
  amount: number;
  date: string;
  paid: boolean;
  divisionType: 'Millesimi' | 'Equally';
}

export interface Document {
  id: string;
  name: string;
  type: string;
  date: string;
  data: string; // base64
}

export interface Event {
  id: string;
  title: string;
  date: string;
  description: string;
  type: 'Deadline' | 'Maintenance' | 'Meeting';
}

export interface AppState {
  owners: Owner[];
  payments: Payment[];
  expenses: Expense[];
  documents: Document[];
  events: Event[];
  settings: {
    condoName: string;
    logo: string | null;
  };
}

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const queryCondoWiki = async (question: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Sei un esperto di diritto condominiale italiano. Rispondi in modo conciso e professionale a questa domanda riguardante la gestione di un piccolo condominio (sotto le 8 unità): ${question}`,
      config: {
        systemInstruction: "Sei un assistente legale specializzato nel Codice Civile italiano e nelle normative sui condomini. Fornisci riferimenti ad articoli di legge quando possibile.",
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Wiki Error:", error);
    return "Spiacente, non ho potuto recuperare le informazioni legali in questo momento.";
  }
};

export const generateProfessionalNotice = async (topic: string, details: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Genera una comunicazione formale per i condomini riguardante: ${topic}. Dettagli aggiuntivi: ${details}`,
      config: {
        systemInstruction: "Sei un amministratore di condominio preciso e cortese. Scrivi una circolare formale da inviare via email.",
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Report Error:", error);
    return "Errore nella generazione del testo.";
  }
};

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, 
  Users, 
  Receipt, 
  Wallet, 
  FileText, 
  Calendar, 
  BookOpen, 
  Mail, 
  BarChart3,
  PlusCircle,
  Menu,
  X
} from 'lucide-react';
import Dashboard from './components/Dashboard';
import OwnersRegistry from './components/OwnersRegistry';
import ExpensesManager from './components/ExpensesManager';
import FinanceTracker from './components/FinanceTracker';
import DocumentLibrary from './components/DocumentLibrary';
import CondoWiki from './components/CondoWiki';
import CalendarView from './components/CalendarView';
import ReportGenerator from './components/ReportGenerator';
import CommunicationCenter from './components/CommunicationCenter';
import { AppState } from './types';

const STORAGE_KEY = 'condo_manage_pro_state';

const initialData: AppState = {
  owners: [],
  payments: [],
  expenses: [],
  documents: [],
  events: [],
  settings: {
    condoName: 'Condominio Bella Vista',
    logo: null,
  }
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : initialData;
  });
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  const updateState = (updater: (prev: AppState) => AppState) => {
    setState(updater);
  };

  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'owners', label: 'Anagrafica', icon: Users },
    { id: 'expenses', label: 'Spese e Preventivi', icon: Receipt },
    { id: 'finances', label: 'Cassa e Bilancio', icon: Wallet },
    { id: 'documents', label: 'Documenti', icon: FileText },
    { id: 'calendar', label: 'Scadenze', icon: Calendar },
    { id: 'communications', label: 'Mailing List', icon: Mail },
    { id: 'reports', label: 'Report', icon: BarChart3 },
    { id: 'wiki', label: 'Wiki Legale', icon: BookOpen },
  ];

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard': return <Dashboard state={state} setActiveTab={setActiveTab} />;
      case 'owners': return <OwnersRegistry state={state} updateState={updateState} />;
      case 'expenses': return <ExpensesManager state={state} updateState={updateState} />;
      case 'finances': return <FinanceTracker state={state} updateState={updateState} />;
      case 'documents': return <DocumentLibrary state={state} updateState={updateState} />;
      case 'calendar': return <CalendarView state={state} updateState={updateState} />;
      case 'reports': return <ReportGenerator state={state} updateState={updateState} />;
      case 'communications': return <CommunicationCenter state={state} />;
      case 'wiki': return <CondoWiki />;
      default: return <Dashboard state={state} setActiveTab={setActiveTab} />;
    }
  };

  return (
    <div className="min-h-screen flex bg-slate-50">
      {/* Sidebar Desktop */}
      <aside className="hidden md:flex flex-col w-64 bg-slate-900 text-white fixed h-full">
        <div className="p-6 border-b border-slate-800 flex items-center gap-2">
          <div className="p-2 bg-indigo-500 rounded-lg">
            <LayoutDashboard size={24} />
          </div>
          <span className="font-bold text-xl tracking-tight">CondoPro</span>
        </div>
        <nav className="flex-1 p-4 space-y-2 overflow-y-auto">
          {navItems.map((item) => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
                activeTab === item.id 
                  ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/30' 
                  : 'text-slate-400 hover:bg-slate-800 hover:text-white'
              }`}
            >
              <item.icon size={20} />
              <span className="font-medium">{item.label}</span>
            </button>
          ))}
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 md:ml-64 flex flex-col min-h-screen">
        {/* Top Header */}
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 sticky top-0 z-30">
          <div className="flex items-center gap-4">
            <button className="md:hidden" onClick={() => setIsMobileMenuOpen(true)}>
              <Menu size={24} />
            </button>
            <h2 className="text-xl font-semibold text-slate-800">
              {navItems.find(i => i.id === activeTab)?.label}
            </h2>
          </div>
          <div className="flex items-center gap-4">
            <div className="hidden sm:flex flex-col items-end">
              <span className="text-sm font-bold text-slate-900">{state.settings.condoName}</span>
              <span className="text-xs text-slate-500">Unità: {state.owners.length}/8</span>
            </div>
            {state.settings.logo ? (
              <img src={state.settings.logo} className="h-10 w-10 object-contain rounded border" alt="Logo" />
            ) : (
              <div className="h-10 w-10 bg-slate-100 rounded flex items-center justify-center border text-slate-400">
                <Receipt size={20} />
              </div>
            )}
          </div>
        </header>

        <div className="p-6">
          {renderContent()}
        </div>
      </main>

      {/* Mobile Menu Overlay */}
      {isMobileMenuOpen && (
        <div className="fixed inset-0 z-50 bg-slate-900/50 backdrop-blur-sm md:hidden">
          <div className="w-64 h-full bg-slate-900 text-white flex flex-col">
            <div className="p-6 flex justify-between items-center border-b border-slate-800">
              <span className="font-bold text-xl">CondoPro</span>
              <button onClick={() => setIsMobileMenuOpen(false)}>
                <X size={24} />
              </button>
            </div>
            <nav className="p-4 space-y-2">
              {navItems.map((item) => (
                <button
                  key={item.id}
                  onClick={() => {
                    setActiveTab(item.id);
                    setIsMobileMenuOpen(false);
                  }}
                  className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl ${
                    activeTab === item.id ? 'bg-indigo-600' : 'text-slate-400'
                  }`}
                >
                  <item.icon size={20} />
                  <span>{item.label}</span>
                </button>
              ))}
            </nav>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { AppState, Owner } from '../types';
import { Plus, Trash2, Edit2, UserPlus } from 'lucide-react';

interface OwnersRegistryProps {
  state: AppState;
  updateState: (updater: (prev: AppState) => AppState) => void;
}

const OwnersRegistry: React.FC<OwnersRegistryProps> = ({ state, updateState }) => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [formData, setFormData] = useState<Omit<Owner, 'id'>>({
    name: '',
    unit: '',
    millesimi: 0,
    email: '',
    phone: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (state.owners.length >= 8) {
      alert("Massimo 8 unità consentite in questa versione.");
      return;
    }
    const newOwner: Owner = {
      ...formData,
      id: crypto.randomUUID()
    };
    updateState(prev => ({
      ...prev,
      owners: [...prev.owners, newOwner]
    }));
    setShowAddModal(false);
    setFormData({ name: '', unit: '', millesimi: 0, email: '', phone: '' });
  };

  const deleteOwner = (id: string) => {
    if (confirm("Sicuro di voler eliminare questo condomino? Verranno rimosse anche le scadenze associate.")) {
      updateState(prev => ({
        ...prev,
        owners: prev.owners.filter(o => o.id !== id)
      }));
    }
  };

  const totalMillesimi = state.owners.reduce((acc, curr) => acc + curr.millesimi, 0);

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Anagrafica Condomini</h2>
          <p className="text-slate-500">Gestione dei proprietari e delle quote millesimali</p>
        </div>
        <button 
          onClick={() => setShowAddModal(true)}
          className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-xl hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-200"
        >
          <Plus size={20} />
          Aggiungi Condomino
        </button>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-6 py-4 text-sm font-bold text-slate-500">Unità</th>
              <th className="px-6 py-4 text-sm font-bold text-slate-500">Proprietario</th>
              <th className="px-6 py-4 text-sm font-bold text-slate-500">Millesimi</th>
              <th className="px-6 py-4 text-sm font-bold text-slate-500">Contatti</th>
              <th className="px-6 py-4 text-sm font-bold text-slate-500 text-right">Azioni</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {state.owners.map(owner => (
              <tr key={owner.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-6 py-4">
                  <span className="bg-slate-100 text-slate-700 px-2 py-1 rounded text-xs font-bold">
                    {owner.unit}
                  </span>
                </td>
                <td className="px-6 py-4 font-medium text-slate-900">{owner.name}</td>
                <td className="px-6 py-4 text-slate-600">{owner.millesimi}/1000</td>
                <td className="px-6 py-4">
                  <div className="flex flex-col text-xs">
                    <span className="text-slate-500">{owner.email}</span>
                    <span className="text-slate-400">{owner.phone}</span>
                  </div>
                </td>
                <td className="px-6 py-4 text-right">
                  <div className="flex justify-end gap-2">
                    <button className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors">
                      <Edit2 size={16} />
                    </button>
                    <button 
                      onClick={() => deleteOwner(owner.id)}
                      className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
            {state.owners.length === 0 && (
              <tr>
                <td colSpan={5} className="px-6 py-12 text-center text-slate-400">
                  <UserPlus className="mx-auto mb-2 opacity-20" size={48} />
                  Nessun condomino registrato.
                </td>
              </tr>
            )}
          </tbody>
          <tfoot className="bg-slate-50/80 font-bold border-t border-slate-100">
            <tr>
              <td className="px-6 py-4" colSpan={2}>Totale Millesimi</td>
              <td className="px-6 py-4 text-indigo-600">{totalMillesimi}/1000</td>
              <td colSpan={2}></td>
            </tr>
          </tfoot>
        </table>
      </div>

      {showAddModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm">
          <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl p-6">
            <h3 className="text-xl font-bold text-slate-800 mb-6">Nuovo Condomino</h3>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Nome e Cognome</label>
                <input 
                  required
                  type="text" 
                  value={formData.name}
                  onChange={e => setFormData({...formData, name: e.target.value})}
                  className="w-full px-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Unità (es. Int 1)</label>
                  <input 
                    required
                    type="text" 
                    value={formData.unit}
                    onChange={e => setFormData({...formData, unit: e.target.value})}
                    className="w-full px-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Millesimi</label>
                  <input 
                    required
                    type="number" 
                    step="0.01"
                    value={formData.millesimi}
                    onChange={e => setFormData({...formData, millesimi: Number(e.target.value)})}
                    className="w-full px-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Email</label>
                <input 
                  type="email" 
                  value={formData.email}
                  onChange={e => setFormData({...formData, email: e.target.value})}
                  className="w-full px-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Telefono</label>
                <input 
                  type="tel" 
                  value={formData.phone}
                  onChange={e => setFormData({...formData, phone: e.target.value})}
                  className="w-full px-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                />
              </div>
              <div className="flex gap-3 mt-6">
                <button 
                  type="button" 
                  onClick={() => setShowAddModal(false)}
                  className="flex-1 py-2 text-slate-600 font-medium bg-slate-100 rounded-xl hover:bg-slate-200"
                >
                  Annulla
                </button>
                <button 
                  type="submit"
                  className="flex-1 py-2 text-white font-medium bg-indigo-600 rounded-xl hover:bg-indigo-700 shadow-lg shadow-indigo-200"
                >
                  Salva
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default OwnersRegistry;

import React, { useState } from 'react';
import { AppState, Expense } from '../types';
import { Plus, Calculator, CheckCircle, XCircle } from 'lucide-react';

interface ExpensesManagerProps {
  state: AppState;
  updateState: (updater: (prev: AppState) => AppState) => void;
}

const ExpensesManager: React.FC<ExpensesManagerProps> = ({ state, updateState }) => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [activeTab, setActiveTab] = useState<'list' | 'estimate'>('list');
  const [selectedExpenseForEstimate, setSelectedExpenseForEstimate] = useState<Expense | null>(null);

  const [formData, setFormData] = useState<Omit<Expense, 'id'>>({
    description: '',
    category: 'Manutenzione',
    amount: 0,
    date: new Date().toISOString().split('T')[0],
    paid: false,
    divisionType: 'Millesimi'
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newExpense: Expense = {
      ...formData,
      id: crypto.randomUUID()
    };
    updateState(prev => ({
      ...prev,
      expenses: [...prev.expenses, newExpense]
    }));
    setShowAddModal(false);
    setFormData({
      description: '',
      category: 'Manutenzione',
      amount: 0,
      date: new Date().toISOString().split('T')[0],
      paid: false,
      divisionType: 'Millesimi'
    });
  };

  const togglePaid = (id: string) => {
    updateState(prev => ({
      ...prev,
      expenses: prev.expenses.map(ex => ex.id === id ? { ...ex, paid: !ex.paid } : ex)
    }));
  };

  const calculateDivision = (expense: Expense) => {
    const totalMillesimi = state.owners.reduce((acc, o) => acc + o.millesimi, 0);
    return state.owners.map(owner => ({
      owner: owner.name,
      unit: owner.unit,
      share: (expense.amount * owner.millesimi) / 1000,
      millesimi: owner.millesimi
    }));
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Spese e Preventivi</h2>
          <p className="text-slate-500">Registra i costi e calcola la divisione millesimale</p>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={() => { setActiveTab('list'); setSelectedExpenseForEstimate(null); }}
            className={`px-4 py-2 rounded-xl text-sm font-medium transition-colors ${activeTab === 'list' ? 'bg-white shadow-sm border border-slate-200 text-indigo-600' : 'text-slate-500 hover:bg-slate-100'}`}
          >
            Lista Spese
          </button>
          <button 
            onClick={() => setActiveTab('estimate')}
            className={`px-4 py-2 rounded-xl text-sm font-medium transition-colors ${activeTab === 'estimate' ? 'bg-white shadow-sm border border-slate-200 text-indigo-600' : 'text-slate-500 hover:bg-slate-100'}`}
          >
            Preventivi / Divisione
          </button>
          <button 
            onClick={() => setShowAddModal(true)}
            className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-xl hover:bg-indigo-700 shadow-lg shadow-indigo-200 ml-2"
          >
            <Plus size={20} />
            Nuova Spesa
          </button>
        </div>
      </div>

      {activeTab === 'list' ? (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b border-slate-100">
              <tr>
                <th className="px-6 py-4 text-sm font-bold text-slate-500">Data</th>
                <th className="px-6 py-4 text-sm font-bold text-slate-500">Descrizione</th>
                <th className="px-6 py-4 text-sm font-bold text-slate-500">Categoria</th>
                <th className="px-6 py-4 text-sm font-bold text-slate-500">Importo</th>
                <th className="px-6 py-4 text-sm font-bold text-slate-500">Stato</th>
                <th className="px-6 py-4 text-sm font-bold text-slate-500 text-right">Azioni</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {state.expenses.map(expense => (
                <tr key={expense.id} className="hover:bg-slate-50/50">
                  <td className="px-6 py-4 text-slate-500 text-sm">
                    {new Date(expense.date).toLocaleDateString()}
                  </td>
                  <td className="px-6 py-4 font-medium text-slate-900">{expense.description}</td>
                  <td className="px-6 py-4">
                    <span className="bg-indigo-50 text-indigo-700 px-2 py-1 rounded text-xs font-medium">
                      {expense.category}
                    </span>
                  </td>
                  <td className="px-6 py-4 font-bold text-slate-900">€{expense.amount.toFixed(2)}</td>
                  <td className="px-6 py-4">
                    <button 
                      onClick={() => togglePaid(expense.id)}
                      className={`flex items-center gap-2 px-3 py-1 rounded-full text-xs font-bold transition-colors ${
                        expense.paid ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'
                      }`}
                    >
                      {expense.paid ? <CheckCircle size={14} /> : <XCircle size={14} />}
                      {expense.paid ? 'Pagata' : 'In attesa'}
                    </button>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button 
                      onClick={() => { setSelectedExpenseForEstimate(expense); setActiveTab('estimate'); }}
                      className="text-indigo-600 hover:text-indigo-800 text-sm font-medium"
                    >
                      Calcola Quota
                    </button>
                  </td>
                </tr>
              ))}
              {state.expenses.length === 0 && (
                <tr>
                  <td colSpan={6} className="px-6 py-12 text-center text-slate-400">
                    Nessuna spesa registrata.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          <div className="lg:col-span-1 bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <h3 className="text-lg font-bold text-slate-800 mb-4">Seleziona Spesa</h3>
            <div className="space-y-2 overflow-y-auto max-h-96 pr-2">
              {state.expenses.map(ex => (
                <button
                  key={ex.id}
                  onClick={() => setSelectedExpenseForEstimate(ex)}
