            </div>

            <div className="pt-12 text-center text-[10px] text-slate-300 uppercase font-medium">
              Documento generato automaticamente via CondoManage Pro - Uso Interno Condominiale
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

