import { GoogleGenAI } from "@google/genai";

// Strictly follow named parameter initialization and use process.env.API_KEY directly
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const queryCondoWiki = async (question: string) => {
  try {
    const response = await ai.models.generateContent({
      // Use gemini-3-pro-preview for advanced legal reasoning tasks
      model: 'gemini-3-pro-preview',
      contents: `Sei un esperto di diritto condominiale italiano. Rispondi in modo conciso e professionale a questa domanda riguardante la gestione di un piccolo condominio (sotto le 8 unità): ${question}`,
      config: {
        systemInstruction: "Sei un assistente legale specializzato nel Codice Civile italiano e nelle normative sui condomini. Fornisci riferimenti ad articoli di legge quando possibile.",
      }
    });
    // Use .text property directly
    return response.text;
  } catch (error) {
    console.error("Gemini Wiki Error:", error);
    return "Spiacente, non ho potuto recuperare le informazioni legali in questo momento.";
  }
};

export const generateProfessionalNotice = async (topic: string, details: string) => {
  try {
    const response = await ai.models.generateContent({
      // Use gemini-3-pro-preview for high-quality professional content generation
      model: 'gemini-3-pro-preview',
      contents: `Genera una comunicazione formale per i condomini riguardante: ${topic}. Dettagli aggiuntivi: ${details}`,
      config: {
        systemInstruction: "Sei un amministratore di condominio preciso e cortese. Scrivi una circolare formale da inviare via email.",
      }
    });
    // Use .text property directly
    return response.text;
  } catch (error) {
    console.error("Gemini Report Error:", error);
    return "Errore nella generazione del testo.";
  }
};

import React, { useState, useRef } from 'react';
import { AppState } from '../types';
import { Download, FileText, Image as ImageIcon, Layout, Users, Loader2 } from 'lucide-react';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

interface ReportGeneratorProps {
  state: AppState;
  updateState: (updater: (prev: AppState) => AppState) => void;
}

const ReportGenerator: React.FC<ReportGeneratorProps> = ({ state, updateState }) => {
  const [reportType, setReportType] = useState<'budget' | 'expenses' | 'owners'>('budget');
  const [isGenerating, setIsGenerating] = useState(false);
  const reportRef = useRef<HTMLDivElement>(null);

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onloadend = () => {
      updateState(prev => ({
        ...prev,
        settings: { ...prev.settings, logo: reader.result as string }
      }));
    };
    reader.readAsDataURL(file);
  };

  const handleDownloadPDF = async () => {
    if (!reportRef.current) return;

    setIsGenerating(true);
    try {
      const element = reportRef.current;
      const canvas = await html2canvas(element, {
        scale: 2, // Higher quality
        useCORS: true,
        logging: false,
        backgroundColor: '#ffffff'
      });

      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');
      const imgProps = pdf.getImageProperties(imgData);
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = (imgProps.height * pdfWidth) / imgProps.width;

      pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      pdf.save(`${state.settings.condoName}_${reportType}_${new Date().toISOString().split('T')[0]}.pdf`);
    } catch (error) {
      console.error('PDF Generation error:', error);
      alert('Errore durante la generazione del PDF. Riprova.');
    } finally {
      setIsGenerating(false);
    }
  };

  const totalPayments = state.payments.reduce((acc, p) => acc + p.amount, 0);
  const totalExpenses = state.expenses.reduce((acc, e) => acc + e.amount, 0);

  return (
    <div className="space-y-6 max-w-5xl mx-auto">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Generazione Report</h2>
          <p className="text-slate-500">Configura ed esporta documenti ufficiali</p>
        </div>
        <div className="flex gap-3">
          <label className="flex items-center gap-2 bg-white border border-slate-200 px-4 py-2 rounded-xl hover:bg-slate-50 cursor-pointer transition-all">
            <ImageIcon size={18} className="text-slate-400" />
            <span className="text-sm font-medium">Carica Logo</span>
            <input type="file" className="hidden" accept="image/*" onChange={handleLogoUpload} />
          </label>
          <button 
            onClick={handleDownloadPDF}
            disabled={isGenerating}
            className="flex items-center gap-2 bg-indigo-600 text-white px-6 py-2 rounded-xl hover:bg-indigo-700 shadow-lg font-bold disabled:opacity-50 transition-all"
          >
            {isGenerating ? <Loader2 size={20} className="animate-spin" /> : <Download size={20} />}
            {isGenerating ? 'Generazione...' : 'Stampa / Esporta'}
          </button>
        </div>
      </div>

      <div className="flex gap-4 mb-8">
        <button 
          onClick={() => setReportType('budget')}
          className={`flex-1 flex items-center justify-center gap-2 p-4 rounded-2xl border transition-all ${reportType === 'budget' ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg' : 'bg-white text-slate-500 border-slate-100 hover:border-slate-300'}`}
        >
          <Layout size={20} />
          <span className="font-bold">Bilancio</span>
        </button>
        <button 
          onClick={() => setReportType('expenses')}
          className={`flex-1 flex items-center justify-center gap-2 p-4 rounded-2xl border transition-all ${reportType === 'expenses' ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg' : 'bg-white text-slate-500 border-slate-100 hover:border-slate-300'}`}
        >
          <FileText size={20} />
          <span className="font-bold">Dettaglio Spese</span>
        </button>
        <button 
          onClick={() => setReportType('owners')}
          className={`flex-1 flex items-center justify-center gap-2 p-4 rounded-2xl border transition-all ${reportType === 'owners' ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg' : 'bg-white text-slate-500 border-slate-100 hover:border-slate-300'}`}
        >
          <Users size={20} />
          <span className="font-bold">Anagrafica</span>
        </button>
      </div>

      {/* Report Preview */}
      <div className="bg-slate-200 p-8 rounded-xl overflow-x-auto">
        <div className="bg-white shadow-2xl rounded-sm p-12 min-h-[297mm] w-[210mm] text-slate-900 mx-auto" ref={reportRef}>
          <div className="flex justify-between items-start border-b-2 border-slate-900 pb-8 mb-8">
            <div>
              {state.settings.logo && <img src={state.settings.logo} className="h-16 mb-4 object-contain" alt="Condo Logo" />}
