  ownerId: string;
  amount: number;
  date: string;
  type: 'Quota' | 'Straordinario';
  description: string;
}

export interface Expense {
  id: string;
  description: string;
  category: string;
  amount: number;
  date: string;
  paid: boolean;
  divisionType: 'Millesimi' | 'Equally';
}

export interface Document {
  id: string;
  name: string;
  type: string;
  date: string;
