                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-1">
                      <span className={`px-1.5 py-0.5 rounded border text-[9px] font-bold uppercase flex items-center gap-1 ${getEventBadgeClass(event.type)}`}>
                        {getEventIcon(event.type)}
                        {event.type}
                      </span>
                      {event.date === today && (
                        <span className="text-[9px] font-black text-red-500 uppercase animate-pulse">Oggi</span>
                      )}
                    </div>
                    <h4 className="font-semibold text-slate-800 text-sm truncate">{event.title}</h4>
                    <p className="text-xs text-slate-500 line-clamp-1">{event.description}</p>
                  </div>
                </div>
              ))
            ) : (
              <div className="h-full flex flex-col items-center justify-center text-slate-400 py-8">
                <AlertCircle className="mb-2 opacity-20" size={48} />
                <p className="text-sm">Nessuna scadenza imminente</p>
              </div>
            )}
          </div>

          <button 
            onClick={() => setActiveTab('calendar')}
            className="w-full mt-6 py-3 text-sm text-indigo-600 font-bold hover:bg-indigo-50 border border-indigo-100 rounded-xl transition-colors flex items-center justify-center gap-2"
          >
            Vedi Calendario Completo
            <TrendingUp size={16} className="rotate-90" />
          </button>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

export interface Owner {
  id: string;
  name: string;
  unit: string;
  millesimi: number;
  email: string;
  phone: string;
}

export interface Payment {
  id: string;
  ownerId: string;
  amount: number;
  date: string;
  type: 'Quota' | 'Straordinario';
  description: string;
}

export interface Expense {
  id: string;
  description: string;
  category: string;
  amount: number;
  date: string;
  dueDate?: string; // Data di scadenza per il pagamento
  paid: boolean;
  divisionType: 'Millesimi' | 'Equally';
}

export interface Document {
  id: string;
  name: string;
  type: string;
  date: string;
  data: string; // base64
}

export interface Event {
  id: string;
  title: string;
  date: string;
  description: string;
  type: 'Deadline' | 'Maintenance' | 'Meeting';
}

export interface CondoSettings {
  condoName: string;
  logo: string | null;
  address: string;
  city: string;
  province: string;
  zipCode: string;
  taxCode: string;
  administrator: string;
  adminPhone: string;
  iban: string;
  notes: string;
}

export interface AppState {
  owners: Owner[];
  payments: Payment[];
  expenses: Expense[];
  documents: Document[];
  events: Event[];
  settings: CondoSettings;
}

import React, { useState } from 'react';
import { AppState, Expense } from '../types';
import { Plus, Calculator, CheckCircle, XCircle, AlertTriangle, Clock } from 'lucide-react';

interface ExpensesManagerProps {
  state: AppState;
  updateState: (updater: (prev: AppState) => AppState) => void;
}

const ExpensesManager: React.FC<ExpensesManagerProps> = ({ state, updateState }) => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [activeTab, setActiveTab] = useState<'list' | 'estimate'>('list');
  const [selectedExpenseForEstimate, setSelectedExpenseForEstimate] = useState<Expense | null>(null);

  const [formData, setFormData] = useState<Omit<Expense, 'id'>>({
    description: '',
    category: 'Manutenzione',
    amount: 0,
    date: new Date().toISOString().split('T')[0],
    dueDate: '',
    paid: false,
    divisionType: 'Millesimi'
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newExpense: Expense = {
      ...formData,
      id: crypto.randomUUID()
    };
    updateState(prev => ({
      ...prev,
      expenses: [...prev.expenses, newExpense]
    }));
    setShowAddModal(false);
    setFormData({
      description: '',
      category: 'Manutenzione',
      amount: 0,
      date: new Date().toISOString().split('T')[0],
      dueDate: '',
      paid: false,
      divisionType: 'Millesimi'
    });
  };

  const togglePaid = (id: string) => {
    updateState(prev => ({
      ...prev,
      expenses: prev.expenses.map(ex => ex.id === id ? { ...ex, paid: !ex.paid } : ex)
    }));
  };

  const calculateDivision = (expense: Expense) => {
    return state.owners.map(owner => ({
      owner: owner.name,
      unit: owner.unit,
      share: (expense.amount * owner.millesimi) / 1000,
      millesimi: owner.millesimi
    }));
  };

  const getExpenseStatus = (expense: Expense) => {
    if (expense.paid) return { label: 'Pagata', color: 'bg-green-100 text-green-700', icon: <CheckCircle size={14} /> };

    const today = new Date().toISOString().split('T')[0];
    if (expense.dueDate && expense.dueDate < today) {
      return { label: 'Scaduta', color: 'bg-red-100 text-red-700 animate-pulse', icon: <AlertTriangle size={14} /> };
    }

    return { label: 'In attesa', color: 'bg-amber-100 text-amber-700', icon: <Clock size={14} /> };
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Spese e Preventivi</h2>
          <p className="text-slate-500">Registra i costi e calcola la divisione millesimale</p>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={() => { setActiveTab('list'); setSelectedExpenseForEstimate(null); }}
            className={`px-4 py-2 rounded-xl text-sm font-medium transition-colors ${activeTab === 'list' ? 'bg-white shadow-sm border border-slate-200 text-indigo-600' : 'text-slate-500 hover:bg-slate-100'}`}
          >
            Lista Spese
          </button>
          <button 
            onClick={() => setActiveTab('estimate')}
            className={`px-4 py-2 rounded-xl text-sm font-medium transition-colors ${activeTab === 'estimate' ? 'bg-white shadow-sm border border-slate-200 text-indigo-600' : 'text-slate-500 hover:bg-slate-100'}`}
          >
            Preventivi / Divisione
          </button>
          <button 
            onClick={() => setShowAddModal(true)}
            className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-xl hover:bg-indigo-700 shadow-lg shadow-indigo-200 ml-2"
          >
            <Plus size={20} />
            Nuova Spesa
          </button>
        </div>
      </div>

      {activeTab === 'list' ? (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b border-slate-100">
              <tr>
                <th className="px-6 py-4 text-sm font-bold text-slate-500">Data Reg.</th>
                <th className="px-6 py-4 text-sm font-bold text-slate-500">Descrizione</th>
                <th className="px-6 py-4 text-sm font-bold text-slate-500">Scadenza</th>
                <th className="px-6 py-4 text-sm font-bold text-slate-500">Importo</th>
                <th className="px-6 py-4 text-sm font-bold text-slate-500">Stato</th>
                <th className="px-6 py-4 text-sm font-bold text-slate-500 text-right">Azioni</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {state.expenses.sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()).map(expense => {
                const status = getExpenseStatus(expense);
                return (
                  <tr key={expense.id} className="hover:bg-slate-50/50 transition-colors">
                    <td className="px-6 py-4 text-slate-500 text-sm">
                      {new Date(expense.date).toLocaleDateString()}
                    </td>
                    <td className="px-6 py-4">
                      <p className="font-medium text-slate-900">{expense.description}</p>
                      <span className="text-[10px] text-slate-400 uppercase font-bold">{expense.category}</span>
                    </td>
                    <td className="px-6 py-4 text-sm">
                      {expense.dueDate ? (
                        <span className={!expense.paid && expense.dueDate < new Date().toISOString().split('T')[0] ? 'text-red-600 font-bold' : 'text-slate-600'}>
                          {new Date(expense.dueDate).toLocaleDateString()}
                        </span>
                      ) : (
                        <span className="text-slate-300 italic">Non imp.</span>
                      )}
                    </td>
                    <td className="px-6 py-4 font-bold text-slate-900">€{expense.amount.toFixed(2)}</td>
                    <td className="px-6 py-4">
                      <button 
                        onClick={() => togglePaid(expense.id)}
                        className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-[10px] font-black uppercase transition-all hover:scale-105 ${status.color}`}
                      >
                        {status.icon}
                        {status.label}
                      </button>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <button 
                        onClick={() => { setSelectedExpenseForEstimate(expense); setActiveTab('estimate'); }}
                        className="text-indigo-600 hover:text-indigo-800 text-sm font-bold flex items-center gap-1 ml-auto"
                      >
                        <Calculator size={14} />
                        Ripartizione
                      </button>
                    </td>
                  </tr>
                );
              })}
              {state.expenses.length === 0 && (
                <tr>
                  <td colSpan={6} className="px-6 py-12 text-center text-slate-400">
                    Nessuna spesa registrata.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          <div className="lg:col-span-1 bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <h3 className="text-lg font-bold text-slate-800 mb-4">Seleziona Spesa</h3>
            <div className="space-y-2 overflow-y-auto max-h-[500px] pr-2">
              {state.expenses.map(ex => (
                <button
                  key={ex.id}
                  onClick={() => setSelectedExpenseForEstimate(ex)}
                  className={`w-full text-left p-4 rounded-xl border transition-all ${
                    selectedExpenseForEstimate?.id === ex.id 
                      ? 'border-indigo-500 bg-indigo-50/50 shadow-sm' 
                      : 'border-slate-100 hover:border-slate-200'
                  }`}
                >
                  <p className="font-bold text-slate-900 line-clamp-1">{ex.description}</p>
                  <div className="flex justify-between mt-1 text-xs">
                    <span className="text-indigo-600 font-bold">€{ex.amount.toFixed(2)}</span>
                    <span className="text-slate-400 italic">{ex.category}</span>
                  </div>
                </button>
              ))}
              {state.expenses.length === 0 && <p className="text-slate-400 text-center py-4">Crea una spesa prima.</p>}
            </div>
          </div>

          <div className="lg:col-span-2 bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            {selectedExpenseForEstimate ? (
              <div className="animate-in fade-in slide-in-from-right-4 duration-300">
                <div className="flex justify-between items-start mb-6">
                  <div>
                    <h3 className="text-xl font-bold text-slate-800">{selectedExpenseForEstimate.description}</h3>
                    <p className="text-slate-500">Ripartizione Millesimale - Importo: <span className="text-slate-900 font-bold">€{selectedExpenseForEstimate.amount.toFixed(2)}</span></p>
                  </div>
                  <Calculator className="text-indigo-400" size={32} />
                </div>

                <div className="space-y-3">
                  {calculateDivision(selectedExpenseForEstimate).map((div, i) => (
                    <div key={i} className="flex items-center justify-between p-4 bg-slate-50 rounded-xl border border-slate-100">
                      <div>
                        <p className="font-bold text-slate-800">{div.owner}</p>
                        <p className="text-xs text-slate-500">{div.unit} ({div.millesimi} mill.)</p>
                      </div>
                      <p className="text-lg font-bold text-indigo-600">€{div.share.toFixed(2)}</p>
                    </div>
                  ))}
                </div>

                <div className="mt-8 pt-6 border-t border-slate-100 flex justify-between items-center">
                  <div className="text-xs text-slate-400 italic">
                    Calcolato sulla base di 1000/1000 millesimi totali.
                  </div>
                  <button className="bg-indigo-600 text-white px-6 py-2 rounded-xl font-bold shadow-lg shadow-indigo-200">
                    Esporta Preventivo PDF
                  </button>
                </div>
              </div>
            ) : (
              <div className="h-full flex flex-col items-center justify-center text-slate-400 space-y-4 py-12">
                <Calculator size={48} className="opacity-20" />
                <p>Seleziona una spesa per vederne la ripartizione tra i condomini</p>
              </div>
            )}
          </div>
        </div>
      )}

      {showAddModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm">
          <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl p-6">
            <h3 className="text-xl font-bold text-slate-800 mb-6">Registra Nuova Spesa</h3>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Descrizione</label>
                <input 
                  required
                  type="text" 
                  value={formData.description}
                  onChange={e => setFormData({...formData, description: e.target.value})}
                  className="w-full px-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                  placeholder="es. Riparazione Citofono"
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Categoria</label>
                  <select 
                    value={formData.category}
                    onChange={e => setFormData({...formData, category: e.target.value})}
                    className="w-full px-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none bg-white"
                  >
                    <option>Manutenzione</option>
                    <option>Utenze</option>
                    <option>Assicurazione</option>
                    <option>Pulizie</option>
                    <option>Giardinaggio</option>
                    <option>Amministrazione</option>
                    <option>Varie</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Importo (€)</label>
                  <input 
                    required
                    type="number" 
                    step="0.01"
                    value={formData.amount}
                    onChange={e => setFormData({...formData, amount: Number(e.target.value)})}
                    className="w-full px-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Data Documento</label>
                  <input 
                    type="date" 
                    value={formData.date}
                    onChange={e => setFormData({...formData, date: e.target.value})}
                    className="w-full px-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Scadenza Pagam.</label>
                  <input 
                    type="date" 
                    value={formData.dueDate}
                    onChange={e => setFormData({...formData, dueDate: e.target.value})}
                    className="w-full px-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                </div>
              </div>
              <div className="flex items-center gap-2 pt-2">
                <input 
                  type="checkbox" 
                  id="paid"
                  checked={formData.paid}
                  onChange={e => setFormData({...formData, paid: e.target.checked})}
                  className="w-5 h-5 text-indigo-600 focus:ring-indigo-500 border-slate-300 rounded"
                />
                <label htmlFor="paid" className="text-sm font-bold text-slate-700">Contrassegna come già pagata</label>
              </div>
              <div className="flex gap-3 mt-6">
                <button 
                  type="button" 
                  onClick={() => setShowAddModal(false)}
                  className="flex-1 py-3 text-slate-600 font-bold bg-slate-100 rounded-xl hover:bg-slate-200 transition-colors"
                >
                  Annulla
                </button>
                <button 
                  type="submit"
                  className="flex-1 py-3 text-white font-bold bg-indigo-600 rounded-xl hover:bg-indigo-700 shadow-lg shadow-indigo-200 transition-all active:scale-95"
                >
                  Salva Spesa
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default ExpensesManager;

import React from 'react';
import { AppState, Event, Expense } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { TrendingUp, TrendingDown, Users, AlertCircle, Wallet, Calendar, Wrench, BellRing, AlertTriangle } from 'lucide-react';

interface DashboardProps {
  state: AppState;
  setActiveTab: (tab: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ state, setActiveTab }) => {
  const totalExpenses = state.expenses.reduce((acc, curr) => acc + curr.amount, 0);
  const totalPayments = state.payments.reduce((acc, curr) => acc + curr.amount, 0);
  const balance = totalPayments - totalExpenses;

  const data = [
    { name: 'Entrate', value: totalPayments, color: '#10b981' },
    { name: 'Uscite', value: totalExpenses, color: '#ef4444' }
  ];

  const today = new Date().toISOString().split('T')[0];
  const upcomingEvents = state.events
    .filter(e => e.date >= today)
    .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
    .slice(0, 4);

  const todayEvents = state.events.filter(e => e.date === today);

  // Calcolo spese scadute e non pagate
  const overdueExpenses = state.expenses.filter(ex => !ex.paid && ex.dueDate && ex.dueDate < today);

  const getEventIcon = (type: string) => {
    switch (type) {
      case 'Deadline': return <BellRing size={16} className="text-red-500" />;
      case 'Maintenance': return <Wrench size={16} className="text-amber-500" />;
      case 'Meeting': return <Users size={16} className="text-indigo-500" />;
      default: return <Calendar size={16} className="text-slate-500" />;
    }
  };

  const getEventBadgeClass = (type: string) => {
    switch (type) {
      case 'Deadline': return 'bg-red-50 text-red-600 border-red-100';
      case 'Maintenance': return 'bg-amber-50 text-amber-600 border-amber-100';
      case 'Meeting': return 'bg-indigo-50 text-indigo-600 border-indigo-100';
      default: return 'bg-slate-50 text-slate-600 border-slate-100';
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {/* Today's Alerts & Overdue Reminders */}
      <div className="space-y-3">
        {todayEvents.length > 0 && (
          <div className="bg-red-50 border-l-4 border-red-500 p-4 rounded-xl flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-red-100 text-red-600 rounded-full animate-pulse">
                <AlertCircle size={20} />
              </div>
              <div>
                <p className="font-bold text-red-800">Scadenze odierne: {todayEvents.length}</p>
                <p className="text-sm text-red-600">{todayEvents.map(e => e.title).join(', ')}</p>
              </div>
            </div>
            <button 
              onClick={() => setActiveTab('calendar')}
              className="text-xs font-black uppercase tracking-widest text-red-700 hover:underline"
            >
              Vedi Calendario
            </button>
          </div>
        )}

        {overdueExpenses.length > 0 && (
          <div className="bg-amber-50 border-l-4 border-amber-500 p-4 rounded-xl flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-amber-100 text-amber-600 rounded-full">
                <AlertTriangle size={20} />
              </div>
              <div>
                <p className="font-bold text-amber-800">Attenzione: {overdueExpenses.length} spese scadute e non pagate!</p>
                <p className="text-sm text-amber-600">Totale da saldare: €{overdueExpenses.reduce((a,c) => a+c.amount, 0).toFixed(2)}</p>
              </div>
            </div>
            <button 
              onClick={() => setActiveTab('expenses')}
              className="text-xs font-black uppercase tracking-widest text-amber-700 hover:underline"
            >
              Gestisci Pagamenti
            </button>
          </div>
        )}
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 hover:shadow-md transition-shadow">
          <div className="flex items-center gap-4 mb-4">
            <div className="p-3 bg-green-50 text-green-600 rounded-xl">
              <TrendingUp size={24} />
            </div>
            <div>
              <p className="text-slate-500 text-sm">Entrate Totali</p>
              <p className="text-2xl font-bold text-slate-900">€{totalPayments.toLocaleString()}</p>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 hover:shadow-md transition-shadow">
          <div className="flex items-center gap-4 mb-4">
            <div className="p-3 bg-red-50 text-red-600 rounded-xl">
              <TrendingDown size={24} />
            </div>
            <div>
              <p className="text-slate-500 text-sm">Spese Totali</p>
              <p className="text-2xl font-bold text-slate-900">€{totalExpenses.toLocaleString()}</p>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 hover:shadow-md transition-shadow">
          <div className="flex items-center gap-4 mb-4">
            <div className="p-3 bg-indigo-50 text-indigo-600 rounded-xl">
              <Users size={24} />
            </div>
            <div>
              <p className="text-slate-500 text-sm">Condomini</p>
              <p className="text-2xl font-bold text-slate-900">{state.owners.length}</p>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 hover:shadow-md transition-shadow">
          <div className="flex items-center gap-4 mb-4">
            <div className="p-3 bg-amber-50 text-amber-600 rounded-xl">
              <Wallet size={24} />
            </div>
            <div>
              <p className="text-slate-500 text-sm">Cassa Attuale</p>
              <p className={`text-2xl font-bold ${balance >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                €{balance.toLocaleString()}
              </p>
            </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Chart Section */}
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Andamento Finanziario</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={data}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} />
                <YAxis axisLine={false} tickLine={false} />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
                <Bar dataKey="value" radius={[8, 8, 0, 0]}>
                  {data.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Deadlines Widget */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col">
          <div className="flex justify-between items-center mb-6">
            <h3 className="text-lg font-bold text-slate-800">Prossime Scadenze</h3>
            <Calendar className="text-slate-300" size={20} />
          </div>

          <div className="space-y-4 flex-1">
            {upcomingEvents.length > 0 ? (
              upcomingEvents.map(event => (
                <div key={event.id} className="group relative flex gap-4 p-3 rounded-xl border border-slate-50 bg-slate-50/50 hover:bg-white hover:border-slate-200 hover:shadow-sm transition-all">
                  <div className={`h-12 w-12 rounded-lg flex flex-col items-center justify-center border flex-shrink-0 bg-white ${event.date === today ? 'border-red-200' : 'border-slate-100'}`}>
                    <span className={`text-[10px] uppercase font-bold ${event.date === today ? 'text-red-500' : 'text-slate-400'}`}>
                      {new Date(event.date).toLocaleString('it', { month: 'short' })}
                    </span>
                    <span className={`text-lg font-bold leading-tight ${event.date === today ? 'text-red-600' : 'text-slate-900'}`}>
                      {new Date(event.date).getDate()}
