            <div className="p-4 bg-red-50 border-b border-red-100 flex items-center gap-2">
              <AlertOctagon size={18} className="text-red-500" />
              <h3 className="font-bold text-red-900 uppercase text-xs tracking-wider">Elenco Morosità</h3>
            </div>
            <div className="divide-y divide-slate-50 max-h-[600px] overflow-y-auto">
              {insolvents.map(({ owner, debt }) => (
                <div key={owner.id} className="p-4 hover:bg-red-50/30 transition-colors">
                  <div className="flex justify-between items-start">
                    <div>
                      <h4 className="font-bold text-slate-900">{owner.name}</h4>
                      <p className="text-xs text-slate-500">{owner.unit} • {owner.millesimi} mill.</p>
                    </div>
                    <div className="text-right">
                      <p className="text-lg font-black text-red-600">€{debt.toFixed(2)}</p>
                      <button 
                        onClick={() => handleGenerateDiffida(owner)}
                        className="text-[10px] font-black uppercase text-indigo-600 hover:underline mt-1 flex items-center gap-1 ml-auto"
                      >
                        <FileText size={12} />
