                      </button>
                    </div>
                  </div>
                </div>
              ))}
              {insolvents.length === 0 && (
                <div className="p-12 text-center">
                  <CheckCircle size={48} className="mx-auto text-green-200 mb-2" />
                  <p className="text-slate-400 italic">Nessun debito rilevato. Tutti i condomini sono in regola!</p>
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="lg:col-span-2">
          {selectedOwner ? (
            <div className="bg-white rounded-2xl border border-slate-100 shadow-sm flex flex-col h-full animate-in fade-in slide-in-from-right-4 duration-300">
              <div className="p-4 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
                <div className="flex items-center gap-2">
                  <Sparkles size={18} className="text-indigo-600" />
                  <h3 className="font-bold text-slate-800">Bozza Diffida Legale: {selectedOwner.name}</h3>
                </div>
                <div className="flex gap-2">
                  <button className="p-2 text-slate-400 hover:text-indigo-600"><Download size={20} /></button>
                  <button className="p-2 text-slate-400 hover:text-indigo-600"><Send size={20} /></button>
                </div>
              </div>
              <div className="p-6 flex-1 overflow-y-auto">
                {loading ? (
                  <div className="h-full flex flex-col items-center justify-center space-y-4 text-slate-400">
                    <Clock size={48} className="animate-spin text-indigo-200" />
                    <p className="font-medium">L'IA sta redigendo il documento legale...</p>
                  </div>
                ) : (
                  <div className="prose prose-slate max-w-none text-sm font-serif leading-relaxed whitespace-pre-wrap">
                    {diffidaText}
                  </div>
                )}
              </div>
              <div className="p-4 border-t border-slate-50 bg-slate-50/50 flex justify-between items-center">
                <p className="text-[10px] text-slate-400 uppercase font-black">Valore Legale: Art. 63 Disp. Att. C.C.</p>
