import React, { useState } from 'react';
import { AppState, Owner, LegalNotice } from '../types';
import { AlertOctagon, FileText, Send, Sparkles, CheckCircle, Download, Clock, Mail } from 'lucide-react';
import { generateLegalWarning } from '../services/geminiService';

interface DebtManagerProps {
  state: AppState;
  updateState: (updater: (prev: AppState) => AppState) => void;
}

const DebtManager: React.FC<DebtManagerProps> = ({ state, updateState }) => {
  const [selectedOwner, setSelectedOwner] = useState<Owner | null>(null);
  const [loading, setLoading] = useState(false);
  const [diffidaText, setDiffidaText] = useState('');
  const [showSuccess, setShowSuccess] = useState(false);

  const totalExpenses = state.expenses.reduce((acc, ex) => acc + ex.amount, 0);

  const getOwnerDebt = (owner: Owner) => {
    const ownerPayments = state.payments
      .filter(p => p.ownerId === owner.id)
      .reduce((acc, p) => acc + p.amount, 0);
    const expectedShare = (totalExpenses * owner.millesimi) / 1000;
    const debt = expectedShare - ownerPayments;
    return debt > 0 ? debt : 0;
  };

  const handleGenerateDiffida = async (owner: Owner) => {
    const debt = getOwnerDebt(owner);
    if (debt <= 0) return;

    setLoading(true);
    setSelectedOwner(owner);
    const text = await generateLegalWarning(owner.name, debt, new Date().toLocaleDateString('it-IT'));
    setDiffidaText(text || '');
    setLoading(false);
  };

  const handleSendEmail = () => {
    if (!selectedOwner || !diffidaText) return;

    // 1. Preparazione link Mailto
    const subject = encodeURIComponent(`[DIF-LEGALE] Sollecito Pagamento - ${state.settings.condoName}`);
    const body = encodeURIComponent(diffidaText);
    const mailtoLink = `mailto:${selectedOwner.email}?subject=${subject}&body=${body}`;

    // 2. Protocollazione automatica per tracciabilità
    const newNotice: LegalNotice = {
      id: crypto.randomUUID(),
      protocolNumber: `DIF-${new Date().getFullYear()}-${Math.floor(1000 + Math.random() * 9000)}`,
      recipientId: selectedOwner.id,
      subject: `Diffida ad adempiere - Debito €${getOwnerDebt(selectedOwner).toFixed(2)}`,
      content: diffidaText,
      date: new Date().toISOString(),
      type: 'Diffida',
      status: 'Inviata'
    };

    updateState(prev => ({
      ...prev,
      legalNotices: [...(prev.legalNotices || []), newNotice]
    }));

    // 3. Apertura client email
    window.location.href = mailtoLink;

    // 4. Feedback
    setShowSuccess(true);
    setTimeout(() => setShowSuccess(false), 3000);
  };

  const insolvents = state.owners
    .map(o => ({ owner: o, debt: getOwnerDebt(o) }))
    .filter(i => i.debt > 0)
    .sort((a, b) => b.debt - a.debt);

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Gestione Insoluti</h2>
          <p className="text-slate-500">Monitoraggio ritardi e recupero crediti</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-1 space-y-4">
          <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
            <div className="p-4 bg-red-50 border-b border-red-100 flex items-center gap-2">
              <AlertOctagon size={18} className="text-red-500" />
              <h3 className="font-bold text-red-900 uppercase text-xs tracking-wider">Elenco Morosità</h3>
            </div>
            <div className="divide-y divide-slate-50 max-h-[600px] overflow-y-auto">
              {insolvents.map(({ owner, debt }) => (
                <div key={owner.id} className="p-4 hover:bg-red-50/30 transition-colors">
                  <div className="flex justify-between items-start">
                    <div>
                      <h4 className="font-bold text-slate-900">{owner.name}</h4>
                      <p className="text-xs text-slate-500">{owner.unit} • {owner.millesimi} mill.</p>
                    </div>
                    <div className="text-right">
                      <p className="text-lg font-black text-red-600">€{debt.toFixed(2)}</p>
                      <button 
                        onClick={() => handleGenerateDiffida(owner)}
                        className="text-[10px] font-black uppercase text-indigo-600 hover:underline mt-1 flex items-center gap-1 ml-auto"
                      >
                        <FileText size={12} />
                        Crea Diffida
                      </button>
                    </div>
                  </div>
                </div>
              ))}
              {insolvents.length === 0 && (
                <div className="p-12 text-center">
                  <CheckCircle size={48} className="mx-auto text-green-200 mb-2" />
                  <p className="text-slate-400 italic">Nessun debito rilevato. Tutti i condomini sono in regola!</p>
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="lg:col-span-2">
          {selectedOwner ? (
            <div className="bg-white rounded-2xl border border-slate-100 shadow-sm flex flex-col h-full animate-in fade-in slide-in-from-right-4 duration-300">
              <div className="p-4 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
                <div className="flex items-center gap-2">
                  <Sparkles size={18} className="text-indigo-600" />
                  <h3 className="font-bold text-slate-800">Bozza Diffida Legale: {selectedOwner.name}</h3>
                </div>
                <div className="flex gap-2">
                  <button 
                    title="Scarica PDF"
                    className="p-2 text-slate-400 hover:text-indigo-600 transition-colors"
                  >
                    <Download size={20} />
                  </button>
                  <button 
                    onClick={handleSendEmail}
                    title="Invia via Email e Protocolla"
                    className="p-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-all flex items-center gap-2 px-3"
                  >
                    <Send size={18} />
                    <span className="text-xs font-bold">Invia e Protocolla</span>
                  </button>
                </div>
              </div>
              <div className="p-6 flex-1 overflow-y-auto relative">
                {showSuccess && (
                  <div className="absolute top-4 left-1/2 -translate-x-1/2 z-10 bg-green-600 text-white px-4 py-2 rounded-full shadow-lg text-xs font-bold flex items-center gap-2 animate-bounce">
                    <CheckCircle size={14} />
                    Documento protocollato e inviato!
                  </div>
                )}

                {loading ? (
                  <div className="h-full flex flex-col items-center justify-center space-y-4 text-slate-400">
                    <Clock size={48} className="animate-spin text-indigo-200" />
                    <p className="font-medium">L'IA sta redigendo il documento legale...</p>
                  </div>
                ) : (
                  <div className="prose prose-slate max-w-none text-sm font-serif leading-relaxed whitespace-pre-wrap p-4 bg-slate-50/30 rounded-xl border border-slate-50">
                    {diffidaText}
                  </div>
                )}
              </div>
              <div className="p-4 border-t border-slate-50 bg-slate-50/50 flex justify-between items-center">
                <div className="flex items-center gap-2">
                  <span className="text-[10px] text-slate-400 uppercase font-black">Valore Legale: Art. 63 Disp. Att. C.C.</span>
                  <span className="h-1 w-1 rounded-full bg-slate-300"></span>
                  <span className="text-[10px] text-indigo-500 font-bold uppercase">Tracciabilità garantita</span>
                </div>
                <button 
                  onClick={() => { setSelectedOwner(null); setDiffidaText(''); }}
                  className="text-xs font-bold text-slate-500 hover:text-slate-700"
                >
                  Chiudi Bozza
                </button>
              </div>
            </div>
          ) : (
            <div className="bg-white rounded-2xl border border-slate-100 shadow-sm flex flex-col items-center justify-center py-24 text-slate-400 border-dashed border-2">
              <AlertOctagon size={48} className="mb-4 opacity-10" />
              <p className="font-medium">Seleziona un condomino moroso per generare una diffida formale</p>
              <p className="text-xs mt-1">L'IA preparerà una messa in mora conforme al Codice Civile</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

